import React, { useState, useEffect } from "react";
import { mockAPI } from "../data/mockData";

const Hero = () => {
  const [bannerData, setBannerData] = useState(null);

  // Simulate API call
  useEffect(() => {
    // Simulate API delay
    setTimeout(() => {
      setBannerData(mockAPI.banner);
    }, 500);
  }, []);

  if (!bannerData) {
    return (
      <section className="relative py-20 px-4 sm:px-6 lg:px-8 overflow-hidden">
        <div className="max-w-7xl mx-auto">
          <div className="flex items-center justify-center h-96">
            <div className="text-white text-xl">Loading...</div>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section
      className="relative py-20 px-4 sm:px-6 lg:px-8 overflow-hidden"
      id="home"
    >
      <div className="max-w-7xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
          {/* Left Content */}
          <div className="space-y-8">
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-black text-white leading-tight">
              {bannerData.headline.split("WITH")[0]}WITH
              <br />
              <span className="text-apex-blue">
                {bannerData.headline.split("WITH")[1]}
              </span>
            </h1>

            <p className="text-lg text-gray-300 leading-relaxed max-w-lg">
              {bannerData.subheadline}
            </p>

            <div className="flex flex-col sm:flex-row gap-4">
              {bannerData.buttons.map((button, index) => (
                <button
                  key={index}
                  className={`${
                    button.primary
                      ? "bg-apex-blue hover:bg-blue-400 text-white"
                      : "bg-transparent border-2 border-apex-blue text-apex-blue hover:bg-apex-blue hover:text-white"
                  } px-8 py-4 rounded-md font-semibold transition-all transform hover:scale-105 text-center`}
                >
                  {button.text}
                </button>
              ))}
            </div>
          </div>

          {/* Right Content - Geometric Design */}
          <div className="relative flex justify-center lg:justify-end">
            <div className="relative w-80 h-80 sm:w-96 sm:h-96 flex items-center justify-center">
              {/* Geometric Network Visualization */}
              <svg className="absolute inset-0 w-full h-full" viewBox="0 0 400 400">
                {/* Central Circle */}
                <circle cx="200" cy="200" r="12" fill="#00D4FF" className="glow-effect" />

                {/* Radiating Lines and Outer Circles */}
                {[0, 45, 90, 135, 180, 225, 270, 315].map((angle, index) => {
                  const radian = (angle * Math.PI) / 180;
                  const x1 = 200 + 30 * Math.cos(radian);
                  const y1 = 200 + 30 * Math.sin(radian);
                  const x2 = 200 + 120 * Math.cos(radian);
                  const y2 = 200 + 120 * Math.sin(radian);

                  return (
                    <g key={index}>
                      <line
                        x1={x1}
                        y1={y1}
                        x2={x2}
                        y2={y2}
                        stroke="#00D4FF"
                        strokeWidth="2"
                        opacity="0.8"
                      />
                      <circle
                        cx={x2}
                        cy={y2}
                        r="6"
                        fill="#00D4FF"
                        opacity="0.9"
                      />
                    </g>
                  );
                })}

                {/* Hexagonal Shape with Connected Circles */}
                {[
                  { x: 200, y: 80 },   // top
                  { x: 280, y: 140 },  // top-right
                  { x: 280, y: 260 },  // bottom-right
                  { x: 200, y: 320 },  // bottom
                  { x: 120, y: 260 },  // bottom-left
                  { x: 120, y: 140 }   // top-left
                ].map((point, index) => {
                  const nextPoint = [
                    { x: 200, y: 80 },
                    { x: 280, y: 140 },
                    { x: 280, y: 260 },
                    { x: 200, y: 320 },
                    { x: 120, y: 260 },
                    { x: 120, y: 140 }
                  ][(index + 1) % 6];

                  return (
                    <g key={`hex-${index}`}>
                      <line
                        x1={point.x}
                        y1={point.y}
                        x2={nextPoint.x}
                        y2={nextPoint.y}
                        stroke="#00D4FF"
                        strokeWidth="1.5"
                        opacity="0.6"
                      />
                      <circle
                        cx={point.x}
                        cy={point.y}
                        r="8"
                        fill="#00D4FF"
                        opacity="0.7"
                      />
                    </g>
                  );
                })}

                {/* Additional Small Circles on Lines */}
                {[
                  { x: 200, y: 150 },  // top-center
                  { x: 250, y: 200 },  // right-center
                  { x: 200, y: 250 },  // bottom-center
                  { x: 150, y: 200 }   // left-center
                ].map((point, index) => (
                  <circle
                    key={`small-${index}`}
                    cx={point.x}
                    cy={point.y}
                    r="4"
                    fill="#00D4FF"
                    opacity="0.5"
                  />
                ))}
                />
                <line
                  x1="200"
                  y1="200"
                  x2="300"
                  y2="200"
                  stroke="#00D4FF"
                  strokeWidth="2"
                  opacity="0.6"
                />
                <line
                  x1="200"
                  y1="200"
                  x2="200"
                  y2="300"
                  stroke="#00D4FF"
                  strokeWidth="2"
                  opacity="0.6"
                />
                <line
                  x1="200"
                  y1="200"
                  x2="100"
                  y2="200"
                  stroke="#00D4FF"
                  strokeWidth="2"
                  opacity="0.6"
                />
                <line
                  x1="120"
                  y1="120"
                  x2="200"
                  y2="100"
                  stroke="#00D4FF"
                  strokeWidth="1"
                  opacity="0.4"
                />
                <line
                  x1="280"
                  y1="120"
                  x2="200"
                  y2="100"
                  stroke="#00D4FF"
                  strokeWidth="1"
                  opacity="0.4"
                />
                <line
                  x1="120"
                  y1="280"
                  x2="200"
                  y2="300"
                  stroke="#00D4FF"
                  strokeWidth="1"
                  opacity="0.4"
                />
                <line
                  x1="280"
                  y1="280"
                  x2="200"
                  y2="300"
                  stroke="#00D4FF"
                  strokeWidth="1"
                  opacity="0.4"
                />
              </svg>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
